if(flow.get("currentWaveCompleted")==true&&flow.get("wavesCompleted")<6){
let wave = flow.get("wave") || 0;  // Default to 0 if undefined or falsy
wave = Number(wave) + 1;            // Convert to number and add 1
flow.set("isWaveStarted",false);
flow.set("wave", wave);
flow.set("currentWaveCompleted",false);

msg.payload = "Starting wave " + flow.get("wave");
return msg;
}

const str = msg.payload;
const numberOnly = str.replace(/\D/g, ''); // Remove all non-digit characters
const number = Number(numberOnly);
msg.payload = number;
flow.set("numMobs", number);
return msg;

if(flow.get("mobSpawned")==true&&flow.get("numMobs")==0){
    flow.set("mobSpawned",false);
    flow.set("currentWaveCompleted",true);

    let wave = flow.get("wavesCompleted") || 0;  // Default to 0 if undefined or falsy
    wave = Number(wave) + 1;            // Convert to number and add 1

    flow.set("wavesCompleted", wave);
    msg.payload = wave;
    return msg;
}

let numMobs = flow.get("numMobs");
let nwMobs = flow.get("nwMobs");

if (numMobs > 0 && nwMobs > 0) {
    let ratio = numMobs / nwMobs;
    let pixelsLit = Math.round(ratio * 6);

    // Clamp pixelsLit between 1 and 6
    pixelsLit = Math.min(Math.max(pixelsLit, 1), 6);

    msg.payload = `1-${pixelsLit},3,green`;
} else {
    // No mobs or invalid nwMobs, show empty or black display
    msg.payload = "1-6,3,black";
}

return msg;
